class Solution:
    def resultGrid(self, image, threshold):
        m, n = len(image), len(image[0])
        region_sum = [[0]*n for _ in range(m)]
        region_cnt = [[0]*n for _ in range(m)]
        for r in range(m-2):
            for c in range(n-2):
                # check all adjacent pairs in 3x3
                valid = True
                for i in range(r, r+3):
                    for j in range(c, c+3):
                        if j+1 <= c+2 and abs(image[i][j] - image[i][j+1]) > threshold:
                            valid = False; break
                        if i+1 <= r+2 and abs(image[i][j] - image[i+1][j]) > threshold:
                            valid = False; break
                    if not valid: break
                if valid:
                    avg = sum(image[i][j] for i in range(r,r+3) for j in range(c,c+3)) // 9
                    for i in range(r,r+3):
                        for j in range(c,c+3):
                            region_sum[i][j] += avg
                            region_cnt[i][j] += 1
        result = []
        for i in range(m):
            row = []
            for j in range(n):
                if region_cnt[i][j] > 0:
                    row.append(region_sum[i][j] // region_cnt[i][j])
                else:
                    row.append(image[i][j])
            result.append(row)
        return result

