var resultGrid = function(image, threshold) {
    const m = image.length, n = image[0].length;
    const rsum = Array.from({length:m}, ()=>new Array(n).fill(0));
    const rcnt = Array.from({length:m}, ()=>new Array(n).fill(0));
    for (let r = 0; r <= m-3; r++) {
        for (let c = 0; c <= n-3; c++) {
            let valid = true;
            outer:
            for (let i = r; i <= r+2; i++) {
                for (let j = c; j <= c+2; j++) {
                    if (j+1 <= c+2 && Math.abs(image[i][j]-image[i][j+1]) > threshold) { valid=false; break outer; }
                    if (i+1 <= r+2 && Math.abs(image[i][j]-image[i+1][j]) > threshold) { valid=false; break outer; }
                }
            }
            if (valid) {
                let s = 0;
                for (let i=r;i<=r+2;i++) for (let j=c;j<=c+2;j++) s+=image[i][j];
                const avg = Math.floor(s/9);
                for (let i=r;i<=r+2;i++) for (let j=c;j<=c+2;j++) { rsum[i][j]+=avg; rcnt[i][j]++; }
            }
        }
    }
    return image.map((row,i)=>row.map((v,j)=>rcnt[i][j]>0?Math.floor(rsum[i][j]/rcnt[i][j]):v));
};
